1	/**
2	 * Calendar Screen (Tab 1)
3	 *
4	 * Training calendar with month-view grid, training type indicators,
5	 * day detail card, and training start flow.
6	 *
7	 * Uses useCalendar hook for data and CalendarComputer for computation.
8	 */
9	
10	import React, { useEffect, useState, useCallback, useMemo } from "react";
11	import { View, StyleSheet, ActivityIndicator, Alert } from "react-native";
12	import { useRouter } from "expo-router";
13	import { Colors, Spacing } from "@utils/constants";
14	import type { CalendarDay, TrainingPlan, TrainingDay } from "../../src/types";
15	import {
16	  CalendarMonthGrid,
17	  CalendarMonthHeader,
18	  CalendarFilterTabs,
19	  CalendarDetailCard,
20	  EmptyCalendar,
21	} from "../../src/components/calendar";
22	import type { FilterType } from "../../src/components/calendar/CalendarFilterTabs";
23	import { getTodayISO, parseISODate } from "../../src/utils/date";
24	
25	// Placeholder hook — the real useCalendar requires DB deps.
26	// In production, inject via context or a provider.
27	// For now, this page manages its own state and accepts injected props.
28	export interface CalendarScreenProps {
29	  /** Active training plan */
30	  plan: TrainingPlan | null;
31	  /** Training days for the plan */
32	  trainingDays: TrainingDay[];
33	  /** Calendar computation hook result */
34	  calendarDays: CalendarDay[];
35	  /** Compute month callback */
36	  computeMonth: (year: number, month: number) => Promise<void>;
37	  /** Skip training day */
38	  skipTrainingDay: (date: string) => Promise<void>;
39	  /** Unskip training day */
40	  unskipTrainingDay: (date: string) => Promise<void>;
41	  /** Loading state */
42	  isLoading: boolean;
43	}
44	
45	export default function CalendarScreen({
46	  plan,
47	  trainingDays: _trainingDays,
48	  calendarDays,
49	  computeMonth,
50	  skipTrainingDay,
51	  unskipTrainingDay,
52	  isLoading: isLoadingProp,
53	}: CalendarScreenProps) {
54	  const router = useRouter();
55	
56	  // Current viewed month (defaults to today)
57	  const today = useMemo(() => parseISODate(getTodayISO()), []);
58	  const [viewYear, setViewYear] = useState(today.year);
59	  const [viewMonth, setViewMonth] = useState(today.month);
60	
61	  // Selected date for detail card
62	  const [selectedDate, setSelectedDate] = useState<string | null>(null);
63	
64	  // Filter type
65	  const [filterType, setFilterType] = useState<FilterType>(null);
66	
67	  // Load calendar data on month change
68	  useEffect(() => {
69	    if (plan) {
70	      computeMonth(viewYear, viewMonth);
71	    }
72	  }, [viewYear, viewMonth, plan, computeMonth]);
73	
74	  // Get selected calendar day
75	  const selectedDay = useMemo(() => {
76	    if (!selectedDate) return null;
77	    return calendarDays.find((d) => d.date === selectedDate) ?? null;
78	  }, [selectedDate, calendarDays]);
79	
80	  // Month navigation
81	  const handlePrevMonth = useCallback(() => {
82	    if (viewMonth === 1) {
83	      setViewMonth(12);
84	      setViewYear((y) => y - 1);
85	    } else {
86	      setViewMonth((m) => m - 1);
87	    }
88	    setSelectedDate(null);
89	  }, [viewMonth]);
90	
91	  const handleNextMonth = useCallback(() => {
92	    if (viewMonth === 12) {
93	      setViewMonth(1);
94	      setViewYear((y) => y + 1);
95	    } else {
96	      setViewMonth((m) => m + 1);
97	    }
98	    setSelectedDate(null);
99	  }, [viewMonth]);
100	
101	  // Date selection
102	  const handleDateSelect = useCallback((date: string) => {
103	    setSelectedDate((prev) => (prev === date ? null : date));
104	  }, []);
105	
106	  // Navigation handlers
107	  const handleStartWorkout = useCallback(
108	    (date: string) => {
109	      router.push({
110	        pathname: "/workout",
111	        params: { date },
112	      });
113	    },
114	    [router],
115	  );
116	
117	  const handleRecordOtherSport = useCallback(
118	    (date: string) => {
119	      router.push({
120	        pathname: "/other-sport",
121	        params: { date },
122	      });
123	    },
124	    [router],
125	  );
126	
127	  const handleBacklogWorkout = useCallback(
128	    (date: string) => {
129	      router.push({
130	        pathname: "/workout",
131	        params: { date, backlog: "true" },
132	      });
133	    },
134	    [router],
135	  );
136	
137	  const handleCreatePlan = useCallback(() => {
138	    router.push("/plan-editor");
139	  }, [router]);
140	
141	  // Skip/Unskip
142	  const handleSkipDay = useCallback(
143	    async (date: string) => {
144	      Alert.alert("跳过训练", "确定要跳过这一天的训练吗？", [
145	        { text: "取消", style: "cancel" },
146	        {
147	          text: "确定",
148	          style: "destructive",
149	          onPress: async () => {
150	            await skipTrainingDay(date);
151	            // Refresh calendar
152	            computeMonth(viewYear, viewMonth);
153	          },
154	        },
155	      ]);
156	    },
157	    [skipTrainingDay, computeMonth, viewYear, viewMonth],
158	  );
159	
160	  const handleUnskipDay = useCallback(
161	    async (date: string) => {
162	      await unskipTrainingDay(date);
163	      computeMonth(viewYear, viewMonth);
164	    },
165	    [unskipTrainingDay, computeMonth, viewYear, viewMonth],
166	  );
167	
168	  // No plan - show empty state
169	  if (!plan) {
170	    return (
171	      <View style={styles.container}>
172	        <EmptyCalendar onCreatePlan={handleCreatePlan} />
173	      </View>
174	    );
175	  }
176	
177	  return (
178	    <View style={styles.container}>
179	      {/* Month header with navigation */}
180	      <CalendarMonthHeader
181	        year={viewYear}
182	        month={viewMonth}
183	        onPrevMonth={handlePrevMonth}
184	        onNextMonth={handleNextMonth}
185	      />
186	
187	      {/* Training type filter tabs */}
188	      <CalendarFilterTabs
189	        activeFilter={filterType}
190	        onFilterChange={setFilterType}
191	      />
192	
193	      {/* Month grid */}
194	      {isLoadingProp ? (
195	        <View style={styles.loadingContainer}>
196	          <ActivityIndicator size="large" color={Colors.accent} />
197	        </View>
198	      ) : (
199	        <CalendarMonthGrid
200	          year={viewYear}
201	          month={viewMonth}
202	          calendarDays={calendarDays}
203	          selectedDate={selectedDate}
204	          onDateSelect={handleDateSelect}
205	          filterType={filterType}
206	        />
207	      )}
208	
209	      {/* Detail card for selected date */}
210	      <CalendarDetailCard
211	        calendarDay={selectedDay}
212	        onStartWorkout={handleStartWorkout}
213	        onRecordOtherSport={handleRecordOtherSport}
214	        onBacklogWorkout={handleBacklogWorkout}
215	        onSkipDay={handleSkipDay}
216	        onUnskipDay={handleUnskipDay}
217	      />
218	    </View>
219	  );
220	}
221	
222	const styles = StyleSheet.create({
223	  container: {
224	    flex: 1,
225	    backgroundColor: Colors.background,
226	    padding: Spacing.contentPadding,
227	  },
228	  loadingContainer: {
229	    flex: 1,
230	    justifyContent: "center",
231	    alignItems: "center",
232	  },
233	});
