1	/**
2	 * CalendarMonthGrid
3	 *
4	 * Renders a 7-column month grid with weekday headers.
5	 * Each day cell shows a colored dot indicating training type.
6	 * Supports selecting a date to show the detail card.
7	 */
8	
9	import React from "react";
10	import { View, Text, TouchableOpacity, StyleSheet } from "react-native";
11	import type { CalendarDay } from "../../types";
12	import { Colors, Typography } from "@utils/constants";
13	import {
14	  WEEKDAY_LABELS_SHORT,
15	  getDaysInMonth,
16	  getFirstDayWeekday,
17	  formatDateISO,
18	  isToday,
19	  getTrainingTypeColor,
20	} from "../../utils/date";
21	
22	export interface CalendarMonthGridProps {
23	  /** Year (e.g. 2026) */
24	  year: number;
25	  /** Month, 1-indexed (1=January) */
26	  month: number;
27	  /** Calendar day data for the month */
28	  calendarDays: CalendarDay[];
29	  /** Currently selected date (YYYY-MM-DD) */
30	  selectedDate: string | null;
31	  /** Called when a date is tapped */
32	  onDateSelect: (date: string) => void;
33	  /** Optional filter for training type (null = show all) */
34	  filterType: "push" | "pull" | "legs" | "custom" | null;
35	}
36	
37	/** Map of dayType to display indicator */
38	function getDayIndicator(day: CalendarDay): {
39	  dotColor: string | null;
40	  isCheck: boolean;
41	  isPartial: boolean;
42	  isSkipped: boolean;
43	  isOtherSport: boolean;
44	} {
45	  switch (day.dayType) {
46	    case "completed":
47	      return {
48	        dotColor: null,
49	        isCheck: true,
50	        isPartial: false,
51	        isSkipped: false,
52	        isOtherSport: false,
53	      };
54	    case "completed_partial":
55	      return {
56	        dotColor: null,
57	        isCheck: true,
58	        isPartial: true,
59	        isSkipped: false,
60	        isOtherSport: false,
61	      };
62	    case "skipped":
63	      return {
64	        dotColor: null,
65	        isCheck: false,
66	        isPartial: false,
67	        isSkipped: true,
68	        isOtherSport: false,
69	      };
70	    case "other_sport":
71	      return {
72	        dotColor: Colors.otherSport,
73	        isCheck: false,
74	        isPartial: false,
75	        isSkipped: false,
76	        isOtherSport: true,
77	      };
78	    case "training":
79	      return {
80	        dotColor: day.trainingDay
81	          ? getTrainingTypeColor(day.trainingDay.training_type)
82	          : Colors.accent,
83	        isCheck: false,
84	        isPartial: false,
85	        isSkipped: false,
86	        isOtherSport: false,
87	      };
88	    case "rest":
89	    default:
90	      return {
91	        dotColor: null,
92	        isCheck: false,
93	        isPartial: false,
94	        isSkipped: false,
95	        isOtherSport: false,
96	      };
97	  }
98	}
99	
100	export function CalendarMonthGrid({
101	  year,
102	  month,
103	  calendarDays,
104	  selectedDate,
105	  onDateSelect,
106	  filterType,
107	}: CalendarMonthGridProps) {
108	  const totalDays = getDaysInMonth(year, month);
109	  const firstWeekday = getFirstDayWeekday(year, month);
110	
111	  // Build a lookup map for calendar days
112	  const dayMap = new Map<string, CalendarDay>();
113	  for (const cd of calendarDays) {
114	    dayMap.set(cd.date, cd);
115	  }
116	
117	  // Build grid cells: empty cells for offset, then day cells
118	  const cells: Array<{
119	    type: "empty" | "day";
120	    date?: string;
121	    day?: number;
122	    calendarDay?: CalendarDay;
123	  }> = [];
124	
125	  // Offset: firstWeekday is 1=Monday, so offset = firstWeekday - 1
126	  for (let i = 0; i < firstWeekday - 1; i++) {
127	    cells.push({ type: "empty" });
128	  }
129	
130	  for (let d = 1; d <= totalDays; d++) {
131	    const dateStr = formatDateISO(year, month, d);
132	    cells.push({
133	      type: "day",
134	      date: dateStr,
135	      day: d,
136	      calendarDay: dayMap.get(dateStr),
137	    });
138	  }
139	
140	  // Check if a day should be dimmed by filter
141	  function isDimmed(calendarDay?: CalendarDay): boolean {
142	    if (!filterType || !calendarDay) return false;
143	    if (calendarDay.dayType === "rest") return false;
144	    return (
145	      calendarDay.trainingDay?.training_type !== filterType &&
146	      calendarDay.dayType !== "other_sport"
147	    );
148	  }
149	
150	  return (
151	    <View style={styles.grid} testID="calendar-month-view">
152	      {/* Weekday headers */}
153	      <View style={styles.headerRow}>
154	        {WEEKDAY_LABELS_SHORT.map((label) => (
155	          <View key={label} style={styles.headerCell}>
156	            <Text style={styles.headerText}>{label}</Text>
157	          </View>
158	        ))}
159	      </View>
160	
161	      {/* Day rows */}
162	      {buildRows(cells).map((row, rowIdx) => (
163	        <View key={rowIdx} style={styles.weekRow}>
164	          {row.map((cell, cellIdx) => {
165	            if (cell.type === "empty") {
166	              return <View key={`empty-${cellIdx}`} style={styles.dayCell} />;
167	            }
168	
169	            const dateStr = cell.date!;
170	            const dayNum = cell.day!;
171	            const calendarDay = cell.calendarDay;
172	            const selected = dateStr === selectedDate;
173	            const today = isToday(dateStr);
174	            const indicator = calendarDay
175	              ? getDayIndicator(calendarDay)
176	              : {
177	                  dotColor: null,
178	                  isCheck: false,
179	                  isPartial: false,
180	                  isSkipped: false,
181	                  isOtherSport: false,
182	                };
183	            const dimmed = isDimmed(calendarDay);
184	
185	            return (
186	              <TouchableOpacity
187	                key={dateStr}
188	                style={[
189	                  styles.dayCell,
190	                  selected && styles.dayCellSelected,
191	                  today && styles.dayCellToday,
192	                ]}
193	                onPress={() => onDateSelect(dateStr)}
194	                activeOpacity={0.6}
195	                accessibilityLabel={`${month}月${dayNum}日`}
196	                accessibilityRole="button"
197	                testID={today ? "day-cell-today" : `day-cell-${dateStr}`}
198	              >
199	                <Text
200	                  style={[
201	                    styles.dayText,
202	                    today && styles.dayTextToday,
203	                    selected && styles.dayTextSelected,
204	                    dimmed && styles.dayTextDimmed,
205	                  ]}
206	                >
207	                  {dayNum}
208	                </Text>
209	
210	                {/* Training type dot */}
211	                {indicator.dotColor && !dimmed && (
212	                  <View
213	                    style={[
214	                      styles.dot,
215	                      { backgroundColor: indicator.dotColor },
216	                    ]}
217	                    testID="training-type-label"
218	                  />
219	                )}
220	
221	                {/* Completed checkmark */}
222	                {indicator.isCheck && !dimmed && (
223	                  <View
224	                    style={[
225	                      styles.checkDot,
226	                      indicator.isPartial && styles.checkDotPartial,
227	                    ]}
228	                  >
229	                    <Text style={styles.checkMark}>
230	                      {indicator.isPartial ? "◐" : "✓"}
231	                    </Text>
232	                  </View>
233	                )}
234	
235	                {/* Skipped indicator */}
236	                {indicator.isSkipped && !dimmed && (
237	                  <View style={styles.skippedDash} />
238	                )}
239	              </TouchableOpacity>
240	            );
241	          })}
242	        </View>
243	      ))}
244	    </View>
245	  );
246	}
247	
248	/**
249	 * Split cells array into rows of 7.
250	 */
251	function buildRows<T>(cells: T[]): T[][] {
252	  const rows: T[][] = [];
253	  for (let i = 0; i < cells.length; i += 7) {
254	    rows.push(cells.slice(i, i + 7));
255	  }
256	  // Pad last row if needed
257	  const lastRow = rows[rows.length - 1];
258	  if (lastRow && lastRow.length < 7) {
259	    while (lastRow.length < 7) {
260	      lastRow.push({ type: "empty" } as T);
261	    }
262	  }
263	  return rows;
264	}
265	
266	const DAY_CELL_SIZE = 44;
267	
268	const styles = StyleSheet.create({
269	  grid: {
270	    width: "100%",
271	  },
272	  headerRow: {
273	    flexDirection: "row",
274	    marginBottom: 4,
275	  },
276	  headerCell: {
277	    flex: 1,
278	    alignItems: "center",
